
import React, { useState, useEffect } from "react";

import "./styles.css"
import { CloseModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt } from "../../../components";

import { updStore, getStore, gen16CodeId, isImageFile, b64toUrl, parseDate, copyToClipboard, parseDateMMDDYYYY } from "../../../stores/Utils";
import { handleDetectLandMark, parseTextAnnotations2BC  } from "../services/customer_fetch_service";


const TextInput = TextInput_Cmpt();


const Svg = SvgIcon_Cmpt();



let filesExt = {
	"png":"image/png",
	"jpg":"image/jpg",
	"jpeg":"image/jpeg",
	"webp":"image/webp",
	"gif":"image/gif",
}






const DashboardImageTools  = ({ data, image, item, title }) => {
	const [obs, set_obs] = useState(1);
	const [init, set_init] = useState(false);

	const fillFromAuto =  (i, v) => {
		let lineText = parseTextAnnotations2BC(getStore("image_text"));
		updStore("generated_form_btc", lineText);
		updObs();
	}

	const SendBackForm =  () => {
		let formD = {...getStore("birth_certificate")};
		let ffm = Object.assign({},formD,getStore("generated_form_btc"));
		updStore("birth_certificate", ffm);
		close();
	}


	const handleLMk =  (i, v) => {
		
		updStore("image_text", v.textAnnotations);
		let lineText = parseTextAnnotations2BC(v.textAnnotations)

		
		updStore("generated_form_btc", lineText);
		updStore("loading_image_text", false);
		updObs();
	}

	const loadBlob = async (im,ext) => {
		var blob = await b64toUrl(im,filesExt[ext]);
		updStore("preview_src", blob);
		validateImage(blob);
	}

	useEffect(() => {
		if(!init){
			let ext = item?.fileName.split('.').pop().toLowerCase();
			if(isImageFile(item?.fileName)){
				if(!getStore("generated_form_btc_loaded")){
					handleDetectLandMark(image,handleLMk );
					loadBlob(image,ext);
					updStore("generated_form_btc_loaded", 1);
				}
			}
		}
	}, [image]);
	


	const updObs =  (v) => {
		set_obs(gen16CodeId());
	}






	const validateImage = (result) => {
		
		var i = new Image();	
		i.onload = function(){
			let dmzImg = {
				oh: i.height,
				ow: i.width,
				h: i.height,
				w: i.width,
			}
			updStore( "preview_dmz",dmzImg);
			updObs()
		};
		if(result){
			i.src = result;
		}
	}	
 
	const updKey =  (k,v) => {
		updStore([k],v);
		updObs()
	}


	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}

	

	return (
		
		<div
		style={{
			maxHeight: "93vh",
			width: "1080px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px 25px"
		}}
		>


			<div className="_dsplFlx " style={{padding: 9 , width: "100%"}}>
				<div style={{maxWidth: 560 ,    height: "90vmin", padding: "5px!important"}}>
				<div className="_dsplFlx " style={{padding: 9}}>
					<div className="">
						<GrayButton label={"Redraw form"} clickHandler={fillFromAuto}/>
					</div>
					<div className="flexSpace"/>
					<div className="">
						<GrayButton label={"Load"} clickHandler={SendBackForm}/>
					</div>
				</div>
				<div>
						
						
						<LabelInput 
							title={"Id:"}
							frmNm={"generated_form_btc"}
							keyfld={"registrationId"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Tomo:"}
							frmNm={"generated_form_btc"}
							keyfld={"tomo"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Folio:"}
							frmNm={"generated_form_btc"}
							keyfld={"folio"}
							updObs={updObs}
						/>

						
						
						<LabelDateInput
							title={"Registration Date:"}
							frmNm={"generated_form_btc"}
							keyfld={"dor"}
							updObs={updObs}
						/>

						<LabelInput 
							title={"Registration City:"}
							frmNm={"generated_form_btc"}
							keyfld={"city_registration"}
							updObs={updObs}
						/>

						<LabelInput 
							title={"Registration State:"}
							frmNm={"generated_form_btc"}
							keyfld={"state_registration"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Abuelo Paterno:"}
							frmNm={"generated_form_btc"}
							keyfld={"grandFather_FatherSide"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Abuela Paterna:"}
							frmNm={"generated_form_btc"}
							keyfld={"grandMother_FatherSide"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Abuelo Materno:"}
							frmNm={"generated_form_btc"}
							keyfld={"grandFather_MotherSide"}
							updObs={updObs}
						/>

						<LabelInput 
							title={"Abuela Materna:"}
							frmNm={"generated_form_btc"}
							keyfld={"grandMother_MotherSide"}
							updObs={updObs}
						/>


						
						<LabelDateInput
							title={"Request Date:"}
							frmNm={"generated_form_btc"}
							keyfld={"dop"}
							updObs={updObs}
						/>
						
						<LabelInput 
							title={"Prepared By:"}
							frmNm={"generated_form_btc"}
							keyfld={"prepared_by"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Revised By:"}
							frmNm={"generated_form_btc"}
							keyfld={"revised_by"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Registration Officer:"}
							frmNm={"generated_form_btc"}
							keyfld={"registration_officer"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Codigo Caso:"}
							frmNm={"generated_form_btc"}
							keyfld={"caseCode"}
							updObs={updObs}
						/>
						<LabelInput 
							title={"Pin:"}
							frmNm={"generated_form_btc"}
							keyfld={"casePin"}
							updObs={updObs}
						/>
						
					</div>
					
				</div>
				<div className="flexSpace"/>
				<div style={{   height: "86vmin", padding: "5px!important"}}>
					{getStore("preview_dmz")?.w?
						<SVG_img image={image} />
					:null}
				</div>
			</div>
			

		</div>
	)

}






export default DashboardImageTools;




const LabelInput  = ({ title,  keyfld, updObs, frmNm }) => {
	const [edit, set_edit] = useState(false);
	const [obs, set_obs] = useState(1);

	
	
	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};

	const success = () => {
		updObs && updObs();
		set_edit(false)
	}

	let label = getStore(frmNm)?.[keyfld];

	return (
		<div className="_dsplFlx dtls">
			<div className="lbl_h_dtls" style={{marginTop:edit?8:1}}>
				{title}
			</div>
			{edit?
				<div className="_dsplFlx">
					<div className="lbl_dtls">
						<TextInput  
							init={label}
							width={240} 
							updChanges={(e)=>updFrm(keyfld,e)}
						/>	
					</div>
					<div className="icon_image " onClick={success}>
						<Svg name={"success"} color={"var(--success)"}/>
					</div>
				</div>
			:
			<div className="lbl_dtls" onClick={()=>set_edit(true)}>
			{label || "click to type" }
			</div>
			}
		</div>
	)
}





const LabelDateInput  = ({ title,  keyfld, updObs, frmNm }) => {
	const [edit, set_edit] = useState(false);
	const [obs, set_obs] = useState(1);

	const [value, set_value] = useState("");

	
	
	const updFrm = (f, v) => {

		let frm2 = getStore(frmNm) || {};
		let parseDate = (new Date(v)).getTime();
		frm2[f] = parseDate;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};

	const success = () => {
		updFrm(keyfld,value);
		updObs && updObs();
		set_edit(false)
	}

	let label = getStore(frmNm)?.[keyfld];

	let labelInput = value || parseDateMMDDYYYY(getStore(frmNm)?.[keyfld]) || "";
	
	
	return (
		<div className="_dsplFlx dtls">
			<div className="lbl_h_dtls" style={{marginTop:edit?8:1}}>
				{title}
			</div>
			{edit?
				<div className="_dsplFlx">
					<div className="lbl_dtls">
						<TextInput  
							init={labelInput}
							width={240} 
							updChanges={set_value}
						/>	
					</div>
					<div className="icon_image " onClick={success}>
						<Svg name={"success"} color={"var(--success)"}/>
					</div>
				</div>
			:
			<div className="lbl_dtls" onClick={()=>set_edit(true)}>
			{parseDate(label) || "click to type" }
			</div>
			}
		</div>
	)
}


