const SVG_img  = ({ image }) => {


	
	
	return (
		<svg 
		
			id={"ssg_business_card_front"}  
			xmlns="http://www.w3.org/2000/svg" 
			width="100%" height="100%" 
			viewBox={`0 0 ${getStore("preview_dmz")?.w} ${getStore("preview_dmz")?.h}`} 
			preserveAspectRatio="xMidYMid meet"
			
		>
			<style type="text/css">
			{`@font-face {
				font-family: "Google Sans";
				src: url(http://fonts.gstatic.com/s/googlesans/v14/4UabrENHsxJlGDuGo1OIlLU94YtzCwY.woff2)

			}`}
			</style>
			<rect width={getStore("preview_dmz")?.w} height={getStore("preview_dmz")?.h} fill="#ffffff"></rect>
			<image width={getStore("preview_dmz")?.w} height={getStore("preview_dmz")?.h} x={0} y={0} xmlnsXlink="http://www.w3.org/1999/xlink" xlinkHref={image}></image> 
			{getStore("image_text")?.map((ta, indta)=> <SvgTextAnnotationItem key={indta + "_tann" } idKey={indta + "_tann" } item={ta} index={indta} />)}
		</svg>
	)
}








const SvgTextAnnotationItem  = ({ item, index, idKey }) => {
	
	const {description, boundingPoly} = item;

	let vert = boundingPoly?.vertices;
	

	let hh =  vert?.[3]?.y - vert?.[0]?.y;
	let ww =  vert?.[1]?.x - vert?.[0]?.x ;


	const handleVisible = (e) =>{
		e.stopPropagation();
		e.preventDefault();
		copyToClipboard(description);
	}

	const handleCm = (e) =>{
		e.stopPropagation();
		e.preventDefault();
	}

	if(index === 0 || !vert?.[1]){
		return null;
	}

	
	
	

	return (
		<rect
			onClick={handleVisible}
			onContextMenu={handleCm}
			width={ww} 
			height={hh}
			fill={"#646cff"}
			fillOpacity="50%"
			x={vert?.[0]?.x }
			y={vert?.[0]?.y} 
		/>
	)

}





